param(
  [string]$WorkRoot='state/checks/r7-h6b-freshness-work',
  [string]$HumanReportPath='state/checks/r7-h6b-freshness-report.md',
  [string]$MachineReportPath='state/checks/r7-h6b-freshness-report.json'
